.help-modal-container {
    background: #fff;
    border-radius: 12px;
    padding: 0;
    box-shadow: 0 8px 32px rgb(0 0 0 / .2);
    max-width: 80vw;
    max-height: 80vh;
    display: flex;
    flex-direction: column
