.help-modal-title-container {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 12px
}

.help-modal-title {
    font-weight: 700;
    color: #333;
    font-size: 18px
}

.help-modal-close {
    position: absolute;
    right: 20px;
    background: none;
    border: none;
    font-size: 24px;
    cursor: pointer;
    color: #666;
    padding: 0;
    width: 30px;
    height: 30px;
    display: flex;
    align-items: center;
    justify-content: right
}

.help-modal-close:hover {
    color: red;
    transform: scale(1.2);
    transition: all 0.8s ease-in-out
}

.language-flags {
    display: flex;
    gap: 8px;
    flex-wrap: wrap;
    margin-top: 5px
}

.flag-btn {
    background: none;
    border: 1px solid #ddd;
    border-radius: 4px;
    padding: 4px 8px;
    font-size: 14px;
    cursor: pointer;
    transition: all 0.2s;
    color: #333;
    min-width: 40px;
    text-align: center
}

.flag-btn:hover {
    background: #f0f0f0;
    border-color: #4a6fa5;
    transform: scale(1.05)
}

.flag-btn.active {
    background: #4a6fa5;
    color: #fff;
    border-color: #4a6fa5
}

.help-content {
    padding: 0 20px 20px 20px;
    overflow-y: auto;
    flex-grow: 1
}

.language-section {
    margin-bottom: 30px
}

.language-title {
    font-weight: 700;
    color: #4a6fa5;
    font-size: 16px;
    margin-bottom: 10px;
    padding-bottom: 5px;
    border-bottom: 2px solid #e0e0e0
}

.instruction-list {
    margin: 0;
    padding-left: 20px
}

.instruction-list li {
    margin-bottom: 8px;
    font-size: 14px;
    color: #333
}

.instruction-list strong {
    color: #4a6fa5
}

.note {
    margin-top: 20px;
    padding: 10px 15px;
    background: #f0f7ff;
    border-left: 4px solid #4a6fa5;
    border-radius: 4px;
    font-size: 13px;
    color: #555
}

.note strong {
    color: #4a6fa5
}

.language-separator {
    height: 2px;
    background: linear-gradient(to right, transparent, #ccc, transparent);
    margin: 25px 0
}

.rtl {
    direction: rtl;
    text-align: right
}

.rtl .instruction-list {
    padding-right: 20px;
    padding-left: 0
}

.rtl .note {
    border-left: none;
    border-right: 4px solid #4a6fa5
}

.copy {
    position: fixed;
    top: 20px;
    right: 20px;
    color: #000;
    background: rgb(255 255 255 / .7);
    padding: 10px;
    border-radius: 5px;
    font-size: 12px;
    pointer-events: none
}
